package python

import (
	"os"
	"path/filepath"
	"testing"
)

func writeFixture(t *testing.T, name, content string) string {
	t.Helper()
	path := filepath.Join(t.TempDir(), name)
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
	return path
}

func TestParsePoetryLockV2SubTablesAndHashes(t *testing.T) {
	path := writeFixture(t, "poetry.lock", `
# This file is automatically @generated by Poetry 1.8.2 and should not be changed by hand.

[[package]]
name = "requests"
version = "2.31.0"
description = "Python HTTP for Humans."
optional = false
python-versions = ">=3.7"
files = [
    {file = "requests-2.31.0-py3-none-any.whl", hash = "sha256:58cd2187c01e70e6e26505bca751777aa9f2ee0b7f4300988b709f44e013003f"},
    {file = "requests-2.31.0.tar.gz", hash = "sha256:942c5a758f98d790eaed1a29cb6eefc7ffb0d1cf7af05c3d2791656dbd6ad1e1"},
]

[package.dependencies]
urllib3 = ">=1.21.1,<3"
name = "should-not-clobber"

[[package]]
name = "internal-lib"
version = "0.1.0"
description = "private"
optional = false
python-versions = ">=3.8"
files = []

[package.source]
type = "legacy"
url = "https://pypi.internal.example/simple"
reference = "internal"

[metadata]
lock-version = "2.0"
python-versions = "^3.11"
content-hash = "abc"
`)
	deps, err := ParseFile(path)
	if err != nil {
		t.Fatal(err)
	}
	if len(deps) != 2 {
		t.Fatalf("expected 2 packages, got %d: %+v", len(deps), deps)
	}
	got := map[string]Dependency{}
	for _, d := range deps {
		got[d.Name] = d
	}
	req := got["requests"]
	if req.Version != "2.31.0" || !req.FromLockfile || !req.Pinned {
		t.Fatalf("requests entry wrong: %+v", req)
	}
	if len(req.Hashes) != 2 {
		t.Fatalf("expected 2 recorded hashes for requests, got %+v", req.Hashes)
	}
	if _, clobbered := got["should-not-clobber"]; clobbered {
		t.Fatalf("[package.dependencies] key clobbered package name: %+v", got)
	}
	internal := got["internal-lib"]
	if internal.Registry != "https://pypi.internal.example/simple" {
		t.Fatalf("poetry [package.source] registry not captured: %+v", internal)
	}
}

func TestParseUVLockSkipsLocalProjectAndCapturesSources(t *testing.T) {
	path := writeFixture(t, "uv.lock", `
version = 1
requires-python = ">=3.11"

[options]
exclude-newer = "2026-01-01T00:00:00Z"

[[package]]
name = "myapp"
version = "0.1.0"
source = { virtual = "." }
dependencies = [
    { name = "requests" },
]

[package.metadata]
requires-dist = [{ name = "requests", specifier = ">=2.31" }]

[[package]]
name = "requests"
version = "2.31.0"
source = { registry = "https://pypi.org/simple" }
sdist = { url = "https://files.pythonhosted.org/packages/requests-2.31.0.tar.gz", hash = "sha256:942c5a758f98d790eaed1a29cb6eefc7ffb0d1cf7af05c3d2791656dbd6ad1e1", size = 110794 }
wheels = [
    { url = "https://files.pythonhosted.org/packages/requests-2.31.0-py3-none-any.whl", hash = "sha256:58cd2187c01e70e6e26505bca751777aa9f2ee0b7f4300988b709f44e013003f", size = 62574 },
]

[[package]]
name = "sibling-tool"
version = "0.2.0"
source = { editable = "tools/sibling" }

[[package]]
name = "patched-lib"
version = "1.0.0"
source = { git = "https://github.com/example/patched-lib?rev=abc123" }
`)
	deps, err := ParseFile(path)
	if err != nil {
		t.Fatal(err)
	}
	got := map[string]Dependency{}
	for _, d := range deps {
		got[d.Name] = d
	}
	if !got["myapp"].LocalSource || !got["sibling-tool"].LocalSource {
		t.Fatalf("virtual/editable packages must be marked local: %+v", got)
	}
	req := got["requests"]
	if req.LocalSource || req.Registry != "https://pypi.org/simple" {
		t.Fatalf("registry package wrong: %+v", req)
	}
	if len(req.Hashes) != 2 {
		t.Fatalf("expected sdist+wheel hashes, got %+v", req.Hashes)
	}
	patched := got["patched-lib"]
	if patched.DirectURL == "" || patched.LocalSource {
		t.Fatalf("git-sourced package must carry DirectURL: %+v", patched)
	}
}

func TestParseRequirementsHashesContinuationsAndDirectRefs(t *testing.T) {
	path := writeFixture(t, "requirements.txt", `
requests==2.31.0 \
    --hash=sha256:58cd2187c01e70e6e26505bca751777aa9f2ee0b7f4300988b709f44e013003f \
    --hash=sha256:942c5a758f98d790eaed1a29cb6eefc7ffb0d1cf7af05c3d2791656dbd6ad1e1
mypkg @ https://example.com/mypkg-1.0-py3-none-any.whl
https://example.com/anonymous-artifact.whl
./vendored/local-pkg
flask==3.0.0 ; python_version >= "3.9"
`)
	deps, err := ParseRequirementsFile(path)
	if err != nil {
		t.Fatal(err)
	}
	got := map[string]Dependency{}
	for _, d := range deps {
		got[d.Name] = d
	}
	req := got["requests"]
	if req.Version != "2.31.0" || len(req.Hashes) != 2 {
		t.Fatalf("hashed pinned requirement not parsed: %+v", req)
	}
	if got["mypkg"].DirectURL != "https://example.com/mypkg-1.0-py3-none-any.whl" {
		t.Fatalf("direct reference not captured: %+v", got["mypkg"])
	}
	if got["flask"].Version != "3.0.0" {
		t.Fatalf("marker requirement not parsed: %+v", got["flask"])
	}
	// URL-only and local-path lines must not produce bogus scan targets.
	if len(deps) != 3 {
		t.Fatalf("expected exactly 3 named dependencies, got %d: %+v", len(deps), deps)
	}
}

func TestParsePipfileLockHashesAndIndexResolution(t *testing.T) {
	path := writeFixture(t, "Pipfile.lock", `{
  "_meta": {
    "sources": [
      {"name": "pypi", "url": "https://pypi.org/simple", "verify_ssl": true},
      {"name": "internal", "url": "https://pypi.internal.example/simple", "verify_ssl": true}
    ]
  },
  "default": {
    "requests": {
      "version": "==2.31.0",
      "hashes": ["sha256:58cd2187c01e70e6e26505bca751777aa9f2ee0b7f4300988b709f44e013003f"],
      "index": "pypi"
    },
    "internal-lib": {"version": "==0.1.0", "index": "internal"},
    "patched-lib": {"git": "https://github.com/example/patched-lib", "ref": "abc123"}
  },
  "develop": {}
}`)
	deps, err := ParseFile(path)
	if err != nil {
		t.Fatal(err)
	}
	got := map[string]Dependency{}
	for _, d := range deps {
		got[d.Name] = d
	}
	req := got["requests"]
	if len(req.Hashes) != 1 || req.Registry != "https://pypi.org/simple" || !req.FromLockfile {
		t.Fatalf("Pipfile.lock depth fields wrong: %+v", req)
	}
	if got["internal-lib"].Registry != "https://pypi.internal.example/simple" {
		t.Fatalf("index name not resolved to URL: %+v", got["internal-lib"])
	}
	if got["patched-lib"].DirectURL == "" {
		t.Fatalf("git entry must carry DirectURL: %+v", got["patched-lib"])
	}
}

func TestNormalizeNamePEP503(t *testing.T) {
	for in, want := range map[string]string{
		"Requests":        "requests",
		"Foo_Bar":         "foo-bar",
		"foo..bar":        "foo-bar",
		"zope.interface":  "zope-interface",
		"typing--EXT_lib": "typing-ext-lib",
	} {
		if got := normalizeName(in); got != want {
			t.Fatalf("normalizeName(%q) = %q, want %q", in, got, want)
		}
	}
}

func TestDedupeMergesManifestAndLockfileEntries(t *testing.T) {
	deps := []Dependency{
		{Name: "requests", Specifier: ">=2.31", SourceFile: "pyproject.toml"},
		{Name: "requests", Version: "2.31.0", Pinned: true, FromLockfile: true, Hashes: []string{"sha256:aaa"}, SourceFile: "poetry.lock"},
		{Name: "requests", Version: "2.31.0", Pinned: true, FromLockfile: true, Hashes: []string{"sha256:aaa", "sha256:bbb"}, SourceFile: "uv.lock"},
		{Name: "urllib3", Version: "2.2.1", Pinned: true, FromLockfile: true, SourceFile: "poetry.lock"},
	}
	out := Dedupe(deps)
	if len(out) != 2 {
		t.Fatalf("expected 2 deduped entries, got %d: %+v", len(out), out)
	}
	var merged Dependency
	for _, d := range out {
		if d.Name == "requests" && d.Version == "2.31.0" {
			merged = d
		}
	}
	if merged.FromLockfile {
		t.Fatalf("manifest entry collapsing into lock pin must mark it direct: %+v", out)
	}
	if len(merged.Hashes) != 2 {
		t.Fatalf("hashes should union: %+v", merged)
	}
	for _, d := range out {
		if d.Name == "urllib3" && !d.FromLockfile {
			t.Fatalf("lock-only entry must stay lockfile-sourced: %+v", d)
		}
	}
}
